CustomField.formula:
/* Closed Won and Closed Lost override */ IF( TEXT(StageName) = "Closed Won", "⚫ Date ⚫ Stage | 🟢 Closed Won - No Need To Qualify", IF( TEXT(StageName) = "Closed Lost", "⚫ Date ⚫ Stage | 🔴 Closed Lost - No Need To Qualify",
/* Normal Case */
/* ALL stations are WHITE → force white Date & Stage */ IF( AND( MEDDPICC_Champion_Status__c = "⚪️", MEDDPICC_Pain_Status__c = "⚪️", MEDDPICC_Decision_Criteria_Status__c = "⚪️", MEDDPICC_Decision_Process_Status__c = "⚪️", MEDDPICC_Economic_Buyer_Status__c = "⚪️", MEDDPICC_Metrics_Status__c = "⚪️", MEDDPICC_Paper_Process_Status__c = "⚪️" ), "⚪️ Date ⚪️ Stage",
/* Otherwise → existing logic */ IF( CONTAINS(medpic_Recommended_Close_Date__c, "🟩"), "🟢 Date ", "🔴 Date " ) & IF( TEXT(medpic_Recommended_Stage__c) = TEXT(StageName), "🟢 Stage", "🔴 Stage" )
)))
